func (o *Task) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "TaskComments":
		rels, ok := retrieved.(TaskCommentSlice)
		if !ok {
			return fmt.Errorf("task cannot load %T as %q", retrieved, name)
		}

		o.R.TaskComments = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Task = o
			}
		}
		return nil
	case "Member":
		rel, ok := retrieved.(*Member)
		if !ok {
			return fmt.Errorf("task cannot load %T as %q", retrieved, name)
		}

		o.R.Member = rel

		if rel != nil {
			rel.R.Tasks = TaskSlice{o}
		}
		return nil
	case "Workspace":
		rel, ok := retrieved.(*Workspace)
		if !ok {
			return fmt.Errorf("task cannot load %T as %q", retrieved, name)
		}

		o.R.Workspace = rel

		if rel != nil {
			rel.R.Tasks = TaskSlice{o}
		}
		return nil
	case "Project":
		rel, ok := retrieved.(*Project)
		if !ok {
			return fmt.Errorf("task cannot load %T as %q", retrieved, name)
		}

		o.R.Project = rel

		if rel != nil {
			rel.R.Tasks = TaskSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("task has no relationship %q", name)
	}
}

type taskPreloader struct {
	Member    func(...psql.PreloadOption) psql.Preloader
	Workspace func(...psql.PreloadOption) psql.Preloader
	Project   func(...psql.PreloadOption) psql.Preloader
}

func buildTaskPreloader() taskPreloader {
	return taskPreloader{
		Member: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Member, MemberSlice](psql.PreloadRel{
				Name: "Member",
				Sides: []psql.PreloadSide{
					{
						From:        Tasks,
						To:          Members,
						FromColumns: []string{"workspace_id", "assignee_id"},
						ToColumns:   []string{"workspace_id", "id"},
					},
				},
			}, Members.Columns.Names(), opts...)
		},
		Workspace: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Workspace, WorkspaceSlice](psql.PreloadRel{
				Name: "Workspace",
				Sides: []psql.PreloadSide{
					{
						From:        Tasks,
						To:          Workspaces,
						FromColumns: []string{"workspace_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Workspaces.Columns.Names(), opts...)
		},
		Project: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Project, ProjectSlice](psql.PreloadRel{
				Name: "Project",
				Sides: []psql.PreloadSide{
					{
						From:        Tasks,
						To:          Projects,
						FromColumns: []string{"workspace_id", "project_id"},
						ToColumns:   []string{"workspace_id", "id"},
					},
				},
			}, Projects.Columns.Names(), opts...)
		},
	}
}

