// LoadTaskComments loads the task's TaskComments into the .R struct
func (o *Task) LoadTaskComments(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.TaskComments = nil

	related, err := o.TaskComments(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.Task = o
	}

	o.R.TaskComments = related
	return nil
}

// LoadTaskComments loads the task's TaskComments into the .R struct
func (os TaskSlice) LoadTaskComments(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	taskComments, err := os.TaskComments(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.TaskComments = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range taskComments {

			if !(o.WorkspaceID == rel.WorkspaceID) {
				continue
			}

			if !(o.ID == rel.TaskID) {
				continue
			}

			rel.R.Task = o

			o.R.TaskComments = append(o.R.TaskComments, rel)
		}
	}

	return nil
}

// LoadMember loads the task's Member into the .R struct
func (o *Task) LoadMember(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.Member = nil

	related, err := o.Member(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.Tasks = TaskSlice{o}

	o.R.Member = related
	return nil
}

// LoadMember loads the task's Member into the .R struct
func (os TaskSlice) LoadMember(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	members, err := os.Member(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range members {

			if !(o.WorkspaceID == rel.WorkspaceID) {
				continue
			}
			if !o.AssigneeID.IsValue() {
				continue
			}

			if !(o.AssigneeID.IsValue() && o.AssigneeID.MustGet() == rel.ID) {
				continue
			}

			rel.R.Tasks = append(rel.R.Tasks, o)

			o.R.Member = rel
			break
		}
	}

	return nil
}

